DROP TABLE IF EXISTS `status_histories`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `status_histories` (
  `id` varchar(191) NOT NULL,
  `visaCaseId` varchar(191) NOT NULL,
  `oldStatus` enum('EN_ATTENTE','EN_TRAITEMENT','RDV_OK','VISA_OK','VISA_REFUSEE') NOT NULL,
  `newStatus` enum('EN_ATTENTE','EN_TRAITEMENT','RDV_OK','VISA_OK','VISA_REFUSEE') NOT NULL,
  `changedBy` varchar(191) NOT NULL,
  `changedAt` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  PRIMARY KEY (`id`),
  KEY `status_histories_visaCaseId_idx` (`visaCaseId`),
  KEY `status_histories_changedBy_idx` (`changedBy`),
  CONSTRAINT `status_histories_changedBy_fkey` FOREIGN KEY (`changedBy`) REFERENCES `users` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `status_histories_visaCaseId_fkey` FOREIGN KEY (`visaCaseId`) REFERENCES `visa_cases` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
